INSERT INTO public.history_timeline (title, description, icon_name, status, locale, sort_order) VALUES
('Danny Chain Founded', 'Danny Chain — an EVM-compatible Layer-1 blockchain — was created to provide fast, low-cost transactions with 10-second block times and minimal gas fees.', 'Blocks', 'done', 'en', 0),
('DanScan & DanDex Launch', 'DanScan.io — the official block explorer with 665K+ blocks and 105K+ wallets — launched alongside DanDex.io, a decentralized exchange for trading tokens on Danny Chain.', 'Globe', 'done', 'en', 1),
('HMOOB Token Mining Begins', 'HMOOB token — built on Danny Chain — launched at hmoob.io with cloud mining, boost plans, and a referral system to grow the Hmong crypto community worldwide.', 'Pickaxe', 'current', 'en', 2),
('Global Expansion & Partnerships', 'Partnering with leading wallets — Bitget Wallet, TokenPocket, and SafePal — each with 10M+ downloads, enabling HMOOB holders to manage their tokens securely across multiple platforms.', 'Rocket', 'upcoming', 'en', 3),
('Tsim Danny Chain', 'Danny Chain — ib lub Layer-1 blockchain uas siv tau EVM — tau tsim los muab kev xa nyiaj ceev, nqi qis nrog 10-vib block thiab nqi gas tsawg.', 'Blocks', 'done', 'hmn', 0),
('Tso DanScan & DanDex', 'DanScan.io — lub official block explorer nrog 665K+ blocks thiab 105K+ wallets — tau tso tawm nrog DanDex.io, ib lub decentralized exchange rau kev trade tokens ntawm Danny Chain.', 'Globe', 'done', 'hmn', 1),
('Pib Mining HMOOB Token', 'HMOOB token — ua haujlwm ntawm Danny Chain — tau tso tawm ntawm hmoob.io nrog kev mining hauv huab, boost plans, thiab referral system los loj hlob Hmoob crypto community thoob ntiaj teb.', 'Pickaxe', 'current', 'hmn', 2),
('Nthuav Dav Thoob Ntiaj Teb', 'Koom tes nrog cov wallets loj — Bitget Wallet, TokenPocket, thiab SafePal — txhua lub muaj 10M+ downloads, pab HMOOB holders tswj lawv cov tokens ruaj ntseg ntawm ntau lub platforms.', 'Rocket', 'upcoming', 'hmn', 3),
('ก่อตั้ง Danny Chain', 'Danny Chain — บล็อกเชน Layer-1 ที่รองรับ EVM — ถูกสร้างขึ้นเพื่อให้ทำธุรกรรมเร็ว ค่าใช้จ่ายต่ำ ด้วย block time 10 วินาทีและค่า gas ต่ำ', 'Blocks', 'done', 'th', 0),
('เปิดตัว DanScan & DanDex', 'DanScan.io — block explorer อย่างเป็นทางการที่มี 665K+ blocks และ 105K+ wallets — เปิดตัวพร้อมกับ DanDex.io ตลาดแลกเปลี่ยนแบบกระจายศูนย์สำหรับ Danny Chain', 'Globe', 'done', 'th', 1),
('เริ่มขุด HMOOB Token', 'HMOOB token — สร้างบน Danny Chain — เปิดตัวที่ hmoob.io พร้อมระบบขุดแบบ Cloud, แผน Boost และระบบ Referral เพื่อขยายชุมชนคริปโตม้ง', 'Pickaxe', 'current', 'th', 2),
('ขยายตัวระดับโลกและพันธมิตร', 'ร่วมมือกับกระเป๋าเงินชั้นนำ — Bitget Wallet, TokenPocket และ SafePal — แต่ละตัวมี 10M+ downloads ช่วยให้ผู้ถือ HMOOB จัดการ token ได้อย่างปลอดภัยบนหลายแพลตฟอร์ม', 'Rocket', 'upcoming', 'th', 3);
INSERT INTO public.token_platforms (name, description, url, icon_name, platform_type, gradient, locale, sort_order) VALUES
('hmoob.io', 'Mine HMOOB tokens via cloud mining. Choose a boost plan to increase your hash rate and earn more tokens daily.', 'https://hmoob.io', 'Pickaxe', 'Mining & Boost', 'from-primary/20 to-amber-500/10', 'en', 0),
('DanDex.io', 'Swap HMOOB for other tokens on Danny Chain''s decentralized exchange. Trade DAN, USDT, and more with low fees.', 'https://dandex.io', 'ArrowRightLeft', 'DEX Trading', 'from-blue-500/15 to-primary/10', 'en', 1),
('DanScan.io', 'Track all HMOOB transactions, verify wallet balances, and explore Danny Chain''s 665K+ blocks and 105K+ addresses.', 'https://danscan.io', 'Globe', 'Block Explorer', 'from-emerald-500/15 to-primary/10', 'en', 2),
('hmoob.io', 'Mine HMOOB tokens los ntawm cloud mining. Xaiv ib qho boost plan los nce koj hash rate thiab tau ntau tokens txhua hnub.', 'https://hmoob.io', 'Pickaxe', 'Mining & Boost', 'from-primary/20 to-amber-500/10', 'hmn', 0),
('DanDex.io', 'Swap HMOOB rau lwm cov tokens ntawm Danny Chain decentralized exchange. Trade DAN, USDT, thiab ntau ntxiv nrog nqi qis.', 'https://dandex.io', 'ArrowRightLeft', 'DEX Trading', 'from-blue-500/15 to-primary/10', 'hmn', 1),
('DanScan.io', 'Taug qab txhua HMOOB transactions, txheeb xyuas wallet balances, thiab tshawb Danny Chain 665K+ blocks thiab 105K+ addresses.', 'https://danscan.io', 'Globe', 'Block Explorer', 'from-emerald-500/15 to-primary/10', 'hmn', 2),
('hmoob.io', 'ขุด HMOOB token ผ่าน Cloud Mining เลือกแผน Boost เพื่อเพิ่ม hash rate และรับ token มากขึ้นทุกวัน', 'https://hmoob.io', 'Pickaxe', 'Mining & Boost', 'from-primary/20 to-amber-500/10', 'th', 0),
('DanDex.io', 'แลกเปลี่ยน HMOOB กับ token อื่นบน DEX ของ Danny Chain เทรด DAN, USDT และอื่นๆ ด้วยค่าธรรมเนียมต่ำ', 'https://dandex.io', 'ArrowRightLeft', 'DEX Trading', 'from-blue-500/15 to-primary/10', 'th', 1),
('DanScan.io', 'ติดตามทุกธุรกรรม HMOOB ตรวจสอบยอดกระเป๋า และสำรวจ Danny Chain ที่มี 665K+ blocks และ 105K+ addresses', 'https://danscan.io', 'Globe', 'Block Explorer', 'from-emerald-500/15 to-primary/10', 'th', 2);
